     else

before_code:
module sync_counter_32bit(
  input clk,
  input rst_n,
  output [31:0] count
);
  reg [31:0] count_reg;
  always @(posedge clk) begin
    if (!rst_n)
      count_reg <= 32'b0;
    else
      count_reg <= count_reg + 1;
  end
  assign count = count_reg;
endmodule

after_code:
module sync_counter_32bit(
  input clk,
  input rst_n,
  output [31:0] count
);
  reg [31:0] count_reg;
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count_reg <= 32'b0;
    else
      count_reg <= count_reg + 1;
  end
  assign count = count_reg;
endmodule
